   281|
   282|/**
   283| * Content resolution: try curated first, then walk the `extends:` chain
   284| * (so yoga/pilates inherit gimnasio's curated content rather than generic
   285| * synthesized copy), then fall back to defaultContentFor() as the floor.
   286| */
   287|function loadContent(type: string): ContentTemplate | null {
   288|  const curated = getContent(type) as ContentTemplate | null
   289|  if (curated) return curated
   290|
   291|  // Walk extends chain — each type.json may declare `extends: "<parent-id>"`.
   292|  const seen = new Set<string>([type])
   293|  let cursor = type
   294|  for (let depth = 0; depth < 8; depth++) {
   295|    const reg = getRegistry(cursor) as { extends?: string } | null
   296|    const parent = reg?.extends
   297|    if (!parent || seen.has(parent)) break
   298|    seen.add(parent)
   299|    const parentContent = getContent(parent) as ContentTemplate | null
   300|    if (parentContent) return parentContent
   301|    cursor = parent
   302|  }
   303|
   304|  // Floor: synthesize from registry data. Lazy-require avoids circular import
   305|  // with content-defaults → static-config.
   306|  // eslint-disable-next-line @typescript-eslint/no-require-imports -- Breaks cycle with content-defaults; ESM dynamic import would force this fn async.
